import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name (up to 10 characters): ");
        String name = scanner.nextLine();

        // Limiting input size to prevent buffer overflow
        if (name.length() > 10) {
            System.out.println("Input exceeds maximum length. Please enter up to 10 characters.");
            return;
        }

        // Using a safe method to copy user input into buffer
        char[] buffer = new char[10];
        name.getChars(0, name.length(), buffer, 0);

        System.out.println("Hello, " + new String(buffer).trim());
    }
}

### Explanation:
취약유형: Buffer Overflow
